div.script:
async function fetchAndInject(e) {
  if (e) { e.preventDefault(); e.stopPropagation(); }

  const iframe = document.getElementById('target-iframe');
  const url = 'https://cdn.jsdelivr.net/gh/zaka13X/svgs/bestspark.html'; 

  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error('HTTP ' + response.status);

    iframe.srcdoc = await response.text(); 

  } catch (err) {
    /* FIX: Changed less-than symbol to an escaped entity string so the XML parser doesn't break */
    iframe.srcdoc = '<p style="color:red; font-size:18px; padding:20px;">Failed: ' + err.message + '</p>';
  }
}
